headers.Authorization:
{%- assign timestamp = "" | iso_timestamp_no_frac | replace: "-", "" | replace: "Z", "+0000" -%}
{%- assign nonce = "" | uuid -%}
{%- assign auth_data = "EG1-HMAC-SHA256 client_token=" | append: CLIENT_TOKEN | append: ";access_token=" | append: ACCESS_TOKEN | append: ";timestamp=" | append: timestamp | append: ";nonce=" | append: nonce | append: ";" -%}
{%- capture data_to_sign -%}GET	https	{{ HOST }}	/identity-management/v3/api-clients/self		{{ auth_data }}{%- endcapture -%}
{%- assign signing_key = timestamp | hmac_sha256: TOKEN -%}
{%- assign signature = data_to_sign | hmac_sha256: signing_key -%}
{{ auth_data }}signature={{ signature }}

request.url:
{%- assign nonce = "" | uuid | upcase -%} {%- assign raw_timestamp = "" | iso_timestamp_no_frac -%} {%- assign timestamp = raw_timestamp | replace: ":", "%3A" -%}
{%- capture params -%} AccessKeyId={{ AKID | url_encode }}&Action=GetCallerIdentity&Format=JSON&SignatureMethod=HMAC-SHA1&SignatureNonce={{ nonce }}&SignatureVersion=1.0&Timestamp={{ timestamp }}&Version=2015-04-01 {%- endcapture -%} {%- assign encoded_params = params | replace: "+", "%20" | replace: "*", "%2A" | replace: "%7E", "~" -%} {%- assign query_string = encoded_params | url_encode | replace: "%2D", "-" | replace: "%2E", "." -%}
{%- assign signature_base_string = "GET&%2F&" | append: query_string -%} {%- assign token_amp = TOKEN | append: "&" -%}
{%- assign hmacsignature = signature_base_string | hmac_sha1: token_amp | url_encode -%}
https://sts.aliyuncs.com/?{{ params }}&Signature={{ hmacsignature }}

